  const [description, setDescription] = useState("");
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskFn = useAction(createTask);
  const togglePriorityFn = useAction(togglePriority);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmed = description.trim();
    if (!trimmed) return;
    await createTaskFn({ description: trimmed });
    setDescription("");
  };

  return (
    <main style={styles.container}>
      <h1 style={styles.heading}>Task Priority List</h1>

      <form onSubmit={handleSubmit} style={styles.form}>
        <input
          type="text"
          placeholder="Enter task description..."
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          style={styles.input}
        />
        <button type="submit" style={styles.addButton}>
          Add Task
        </button>
      </form>

      {isLoading && <p style={styles.status}>Loading tasks...</p>}
      {error && <p style={{ ...styles.status, color: "#e53e3e" }}>Error: {error.message}</p>}

      {tasks && tasks.length === 0 && (
        <p style={styles.status}>No tasks yet. Add one above!</p>
      )}

      <ul style={styles.list}>
        {tasks &&
          tasks.map((task) => (
            <li key={task.id} style={styles.taskItem}>
              <div style={styles.taskInfo}>
                <span style={styles.taskDescription}>{task.description}</span>
                <span
                  style={{
                    ...styles.priorityBadge,
                    backgroundColor:
                      task.priority === "High" ? "#e53e3e" : "#3182ce",
                  }}
                >
                  {task.priority}
                </span>
              </div>
              <button
                onClick={() => togglePriorityFn({ id: task.id })}
                style={styles.toggleButton}
              >
                Toggle Priority
              </button>
            </li>
          ))}
      </ul>
    </main>
  );
}

